import React from 'react';
import './Header.css';

const Header = ({ onShareClick, onChatClick }) => {
  const scrollToSection = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <header className="header">
      <div className="header-content">
        <div className="logo">
          <span className="logo-icon">💜</span>
          <span className="logo-text">Share Talk, Heal</span>
        </div>
        <nav className="nav">
          <button className="nav-link" onClick={() => scrollToSection('home')}>Home</button>
          <button className="nav-link" onClick={() => scrollToSection('resources')}>Resources</button>
          <button className="nav-link" onClick={() => scrollToSection('notes')}>Anonymous Notes</button>
          <button className="nav-link" onClick={() => scrollToSection('about')}>About</button>
          <button className="nav-button" onClick={onShareClick}>
            Chat with someone
          </button>
        </nav>
      </div>
    </header>
  );
};

export default Header;
